UPDATE subjects SET names = '{"en": "Counting", "ar": "العد", "bg": "Броене", "zh": "计数", "hr": "Brojanje", "cs": "Počítání", "da": "Tæller", "nl": "Tellen", "et": "Loendamine", "fi": "Laskeminen", "fr": "Comptage", "de": "Zählen", "el": "Μέτρηση", "hi": "गिनती", "hu": "Számolás", "id": "Menghitung", "ga": "Comhaireamh", "it": "Conteggio", "ja": "数え方", "ko": "계수하기", "lv": "Skaitīšana", "lt": "Skaičiavimas", "mt": "Għadd", "pl": "Liczenie", "pt": "Contagem", "ro": "Numărare", "sk": "Počítanie", "sl": "Štetje", "es": "Contar", "sv": "Räkna", "tl": "Pagbilang", "tr": "Sayma", "uk": "Лічба", "vi": "Đếm"}', descriptions = '{"en": "Practice counting from 0 to 10 with interactive objects.", "ar": "تدرب على العد من ٠ إلى ١٠ باستخدام كائنات تفاعلية.", "bg": "Упражнявайте броенето от 0 до 10 с интерактивни обекти.", "zh": "通过互动对象练习从 〇 到 十 的计数。", "hr": "Vježbajte brojanje od 0 do 10 s interaktivnim objektima.", "cs": "Procvičujte počítání od 0 do 10 s interaktivními objekty.", "da": "Øv dig i at tælle fra 0 til 10 med interaktive objekter.", "nl": "Oefen met tellen van 0 tot 10 met interactieve objecten.", "et": "Harjutage loendamist 0-st 10-ni interaktiivsete objektidega.", "fi": "Harjoittele laskemista 0:sta 10:een interaktiivisten kohteiden avulla.", "fr": "Entraînez-vous à compter de 0 à 10 avec des objets interactifs.", "de": "Üben Sie das Zählen von 0 bis 10 mit interaktiven Objekten.", "el": "Εξασκηθείτε στο μέτρημα από το 0 έως το 10 με διαδραστικά αντικείμενα.", "hi": "इंटरैक्टिव वस्तुओं के साथ ० से १० तक गिनती का अभ्यास करें।", "hu": "Gyakorolja a számolást 0-tól 10-ig interaktív objektumokkal.", "id": "Latih menghitung dari 0 hingga 10 dengan objek interaktif.", "ga": "Cleachtadh comhaireamh ó 0 go 10 le rudaí idirghníomhacha.", "it": "Esercitati a contare da 0 a 10 con oggetti interattivi.", "ja": "インタラクティブなオブジェクトを使って 〇 から 十 までの数え方を練習しましょう。", "ko": "대화형 물체를 사용하여 영에서 십까지 세는 연습을 해보세요.", "lv": "Vingrināties skaitīt no 0 līdz 10 ar interaktīviem objektiem.", "lt": "Mokykitės skaičiuoti nuo 0 iki 10 naudodami interaktyvius objektus.", "mt": "Ipprattika l-għadd minn 0 sa 10 b''oġġetti interattivi.", "pl": "Ćwicz liczenie od 0 do 10 za pomocą interaktywnych obiektów.", "pt": "Pratique a contagem de 0 a 10 com objetos interativos.", "ro": "Exersați număratul de la 0 la 10 cu obiecte interactive.", "sk": "Precvičujte počítanie od 0 do 10 s interaktívnymi objektmi.", "sl": "Vadite štetje od 0 do 10 z interaktivnimi predmeti.", "es": "Practica contar del 0 al 10 con objetos interactivos.", "sv": "Öva på att räkna från 0 till 10 med interaktiva objekt.", "tl": "Magsanay magbilang mula 0 hanggang 10 gamit ang mga interactive na bagay.", "tr": "Etkileşimli nesnelerle 0''dan 10''a kadar sayma alıştırması yapın.", "uk": "Практикуйте рахунок від 0 до 10 за допомогою інтерактивних об’єктів.", "vi": "Luyện tập đếm từ 0 đến 10 với các đồ vật tương tác."}', updated_at = CURRENT_TIMESTAMP WHERE id = '68232807-b9cd-4cff-872c-c398444f85e2';
UPDATE subjects SET names = '{"en": "Numbers", "ar": "أرقام", "bg": "Числа", "zh": "数字", "hr": "Brojevi", "cs": "Čísla", "da": "Tal", "nl": "Getallen", "et": "Numbrid", "fi": "Numerot", "fr": "Nombres", "de": "Zahlen", "el": "Αριθμοί", "hi": "संख्याएं", "hu": "Számok", "id": "Angka", "ga": "Uimhreacha", "it": "Numeri", "ja": "数字", "ko": "숫자", "lv": "Skaitļi", "lt": "Skaičiai", "mt": "Numri", "pl": "Liczby", "pt": "Números", "ro": "Numere", "sk": "Čísla", "sl": "Številke", "es": "Números", "sv": "Nummer", "tl": "Numero", "tr": "Sayılar", "uk": "Числа", "vi": "Các con số"}', descriptions = '{"en": "Learn to recognize and name numbers from 0 to 10.", "ar": "تعلم التعرف على الأرقام وتسميتها من ٠ إلى ١٠.", "bg": "Научете се да разпознавате и назовавате числата от 0 до 10.", "zh": "学习识别和命名 〇 到 十 的数字。", "hr": "Naučite prepoznavati i imenovati brojeve od 0 do 10.", "cs": "Naučte se poznávat a pojmenovávat čísla od 0 do 10.", "da": "Lær at genkende og navngive tal fra 0 til 10.", "nl": "Leer cijfers van 0 tot 10 herkennen en benoemen.", "et": "Õppige tundma ja nimetama numbreid 0-st 10-ni.", "fi": "Opi tunnistamaan ja nimeämään numerot 0–10.", "fr": "Apprenez à reconnaître et à nommer les nombres de 0 à 10.", "de": "Lernen Sie, Zahlen von 0 bis 10 zu erkennen und zu benennen.", "el": "Μάθετε να αναγνωρίζετε και να ονομάζετε αριθμούς από το 0 έως το 10.", "hi": "० से १० तक की संख्याओं को पहचानना और नाम देना सीखें।", "hu": "Tanulja meg felismerni és megnevezni a számokat 0-tól 10-ig.", "id": "Belajar mengenali dan memberi nama angka dari 0 hingga 10.", "ga": "Foghlaim conas uimhreacha ó 0 go 10 a aithint agus a ainmniú.", "it": "Impara a riconoscere e nominare i numeri da 0 a 10.", "ja": "〇 から 十 までの数字を認識して名前を付けることを学びましょう。", "ko": "영에서 십까지의 숫자를 인식하고 이름을 짓는 방법을 배워보세요.", "lv": "Iemācieties atpazīt un nosaukt skaitļus no 0 līdz 10.", "lt": "Išmokite atpažinti ir pavadinti skaičius nuo 0 iki 10.", "mt": "Tgħallem tagħraf u ssemmi n-numri minn 0 sa 10.", "pl": "Naucz się rozpoznawać i nazywać liczby od 0 do 10.", "pt": "Aprenda a reconhecer e nomear números de 0 a 10.", "ro": "Învățați să recunoașteți și să numiți numerele de la 0 la 10.", "sk": "Naučte sa rozpoznávať a pomenovávať čísla od 0 do 10.", "sl": "Naučite se prepoznati in poimenovati številke od 0 do 10.", "es": "Aprende a reconocer y nombrar números del 0 al 10.", "sv": "Lär dig känna igen och namnge siffror från 0 till 10.", "tl": "Matutong kilalanin at pangalanan ang mga numero mula 0 hanggang 10.", "tr": "0''dan 10''a kadar olan sayıları tanımayı ve adlandırmayı öğrenin.", "uk": "Навчіться впізнавати та називати числа від 0 до 10.", "vi": "Học cách nhận biết và đặt tên các con số từ 0 đến 10."}', updated_at = CURRENT_TIMESTAMP WHERE id = 'bc354f43-f9be-42a9-a7bc-ac400bd5e310';
